#!/usr/bin/env python3
"""Generate 30-question quizzes for Astronomy Unit 1 (Lessons 1.1-1.7).
Each quiz: 10 easy, 10 vocabulary, 10 scenario questions.
"""
import json, os

def q(num, text, options_data, explanation):
    """Helper to build a question dict."""
    opts = []
    for t, correct in options_data:
        opts.append({"text": t, "is_correct": correct, "data_i18n": None})
    return {
        "question_number": num,
        "question_text": text,
        "attempted": 2,
        "data_i18n": None,
        "options": opts,
        "explanation": explanation
    }

def write_quiz(path, unit, lesson, title, questions):
    data = {
        "unit": unit,
        "lesson_number": lesson,
        "title": title,
        "course": "Astronomy",
        "quiz_questions": questions
    }
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "w", encoding="utf-8") as f:
        json.dump(data, f, indent=2, ensure_ascii=False)
    print(f"  Wrote {path} — {len(questions)} questions")

